fn solve(nums: Vec<i64>, queries: Vec<Vec<i64>>) -> Vec<i64> {
    fn popcount(x: i64) -> i64 {
        let mut count = 0;
        let mut x = x;
        while x != 0 {
            count += x & 1;
            x >>= 1;
        }
        count
    }

    fn get_popcount_depth(x: i64) -> i64 {
        let mut depth = 0;
        let mut current = x;
        while current > 0 {
            current = popcount(current);
            depth += 1;
        }
        depth
    }

    let n = nums.len();
    let mut depth_map = vec![0; n];
    for i in 0..n {
        depth_map[i] = get_popcount_depth(nums[i]);
    }

    // Segment tree implementation
    struct SegmentTree {
        size: usize,
        tree: Vec<i64>,
    }

    impl SegmentTree {
        fn new(data: Vec<i64>) -> Self {
            let size = 1;
            while size < data.len() {
                size <<= 1;
            }
            let mut tree = vec![0; 2 * size];
            for i in 0..data.len() {
                tree[size + i] = data[i];
            }
            for i in (size / 2)..size {
                tree[i] = tree[2 * i] + tree[2 * i + 1];
            }
            SegmentTree { size, tree }
        }

        fn update(&mut self, pos: usize, value: i64) {
            let pos = self.size + pos;
            self.tree[pos] = value;
            let mut pos = pos / 2;
            while pos >= 1 {
                self.tree[pos] = self.tree[2 * pos] + self.tree[2 * pos + 1];
                pos /= 2;
            }
        }

        fn query(&self, l: usize, r: usize) -> i64 {
            let mut res = 0;
            let l += self.size;
            let r += self.size;
            while l <= r {
                if l % 2 == 1 {
                    res += self.tree[l];
                    l += 1;
                }
                if r % 2 == 0 {
                    res += self.tree[r];
                    r -= 1;
                }
                l /= 2;
                r /= 2;
            }
            res
        }
    }

    let mut st = SegmentTree::new(depth_map);
    let mut answer = Vec::new();

    for query in queries {
        if query[0] == 1 {
            let l = query[1] as usize;
            let r = query[2] as usize;
            let k = query[3] as usize;
            // Since the segment tree stores the depth, we need to count how many elements in [l, r] have depth equal to k
            // This is not directly supported by the segment tree, so we need to use a different approach
            // For the purpose of this problem, we'll use a simple approach for the given constraints
            let mut count = 0;
            for i in l..=r {
                if depth_map[i] == k as i64 {
                    count += 1;
                }
            }
            answer.push(count as i64);
        } else {
            let idx = query[1] as usize;
            let val = query[2];
            nums[idx] = val;
            let old_depth = depth_map[idx];
            let new_depth = get_popcount_depth(val);
            depth_map[idx] = new_depth;
            st.update(idx, new_depth);
        }
    }

    answer
}
