                l >>= 1;
                r >>= 1;
            }
            return res;
        }
    }

    // Create segment tree for depth values
    const st = new SegmentTree(depthMap);

    // Process queries
    for (const query of queries) {
        if (query[0] === 1) {
            const [l, r, k] = query.slice(1);
            const count = st.query(l, r);
            answer.push(count);
        } else {
            const [idx, val] = query.slice(1);
            // Update the value and its depth
            const oldVal = nums[idx];
            const newVal = val;
            nums[idx] = newVal;
            const oldDepth = depthMap[idx];
            const newDepth = getPopcountDepth(newVal);
            depthMap[idx] = newDepth;
            st.update(idx, newDepth);
        }
    }

    return answer;
}

function getPopcountDepth(x) {
    let depth = 0;
    while (x > 0) {
        x = popcount(x);
        depth++;
    }
    return depth;
}

function popcount(x) {
    let count = 0;
    while (x) {
        count += x & 1;
        x >>>= 1;
    }
    return count;
}
